import { KeyExpansion } from './keyExpansion.js'; import { SubNibble } from './subNibble.js'; import { ShiftRows } from './shiftRows.js'; import { MixColumns } from './mixColumns.js'; import { logStep } from './logger.js';
const nibbles=n=>[n>>12&15,n>>8&15,n>>4&15,n&15], xor=(s,k)=>s.map((v,i)=>v^nibbles(k)[i]);
export const AddRoundKey = xor;
export function Encrypt(input,key){const expansion=KeyExpansion(key), steps=[]; let s=nibbles(input), next=xor(s,expansion.keys[0]);steps.push(logStep('Initial','Initial AddRoundKey (K0)','XOR state awal dengan K0.',s,next));s=next; next=SubNibble(s);steps.push(logStep('Round 1','SubNibbles','Substitusi setiap nibble melalui S-Box.',s,next));s=next;next=ShiftRows(s);steps.push(logStep('Round 1','ShiftRows','Baris kedua state digeser satu posisi.',s,next));s=next;let mixed=MixColumns(s);next=mixed.state;steps.push(logStep('Round 1','MixColumns','Transformasi setiap kolom dengan matriks [1 4; 4 1].',s,next,mixed.calculation));s=next;next=xor(s,expansion.keys[1]);steps.push(logStep('Round 1','AddRoundKey (K1)','XOR state dengan round key K1.',s,next));s=next;next=SubNibble(s);steps.push(logStep('Round 2','SubNibbles','Substitusi setiap nibble melalui S-Box.',s,next));s=next;next=ShiftRows(s);steps.push(logStep('Round 2','ShiftRows','Baris kedua state digeser satu posisi.',s,next));s=next;next=xor(s,expansion.keys[2]);steps.push(logStep('Round 2','AddRoundKey (K2)','XOR state dengan K2. Round akhir tidak memakai MixColumns.',s,next)); return {output:next,steps,expansion};}
export { nibbles, xor };
